import React, { useState, useContext } from 'react';
import { 
  Star, 
  Heart, 
  Share2, 
  Bookmark, 
  TrendingUp, 
  Users, 
  Brain, 
  Trophy,
  Play,
  X,
  Loader
} from 'lucide-react';

// Mock AuthContext for demo
const AuthContext = React.createContext({
  isAuthenticated: true,
});

// Mock services
const rateMovie = async (data) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ rating: data.rating }), 500);
  });
};

const checkUserRating = async (movieId) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ has_rated: false }), 300);
  });
};

const MovieCard = ({ 
  movie, 
  showRecommendationScore = false, 
  recommendationSources = [], 
  onRatingUpdate = null 
}) => {
  // Use proper fallback if no movie prop is provided
  const movieData = movie || {
    id: 1,
    title: "Inception",
    year: 2010,
    poster_url: "https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop",
    avg_rating: 4.5,
    rating_count: 1247,
    plot: "A thief who enters the dreams of others to steal their secrets from their subconscious gets a chance to have his criminal record erased in exchange for one final job.",
    genres: ["Action", "Sci-Fi", "Thriller", "Drama"],
    recommendation_score: 0.85
  };

  const { isAuthenticated } = useContext(AuthContext);
  const [showQuickRate, setShowQuickRate] = useState(false);
  const [quickRating, setQuickRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [isRating, setIsRating] = useState(false);
  const [userRating, setUserRating] = useState(null);

  React.useEffect(() => {
    if (isAuthenticated && movieData.id) {
      fetchUserRating();
    }
  }, [isAuthenticated, movieData.id]);

  const fetchUserRating = async () => {
    try {
      const ratingData = await checkUserRating(movieData.id);
      if (ratingData.has_rated) {
        setUserRating(ratingData.rating);
      }
    } catch (error) {
      // User hasn't rated this movie, which is fine
    }
  };

  const handleQuickRate = async (rating) => {
    if (!isAuthenticated) return;

    setIsRating(true);
    try {
      const ratingData = await rateMovie({
        movie_id: movieData.id,
        rating: rating,
        review: ''
      });

      setUserRating(ratingData.rating);
      setShowQuickRate(false);

      if (onRatingUpdate) {
        onRatingUpdate(movieData.id, rating);
      }
    } catch (error) {
      console.error('Error rating movie:', error);
      alert('Failed to rate movie. Please try again.');
    } finally {
      setIsRating(false);
    }
  };

  const renderStars = (rating, interactive = false, size = 'small') => {
    const stars = [];
    const maxStars = 5;
    const displayRating = interactive ? (hoverRating || quickRating) : rating;
    const sizeMap = { small: 14, medium: 18, large: 22 };
    const iconSize = sizeMap[size];

    for (let i = 1; i <= maxStars; i++) {
      const filled = i <= displayRating;
      stars.push(
        <span
          key={i}
          style={{
            cursor: interactive ? 'pointer' : 'default',
            transition: 'all 0.2s ease',
            transform: interactive && hoverRating === i ? 'scale(1.1)' : 'scale(1)',
            color: filled ? '#ffd700' : 'rgba(255, 255, 255, 0.5)',
            textShadow: filled ? '0 0 3px rgba(255, 215, 0, 0.5)' : 'none',
            fontSize: `${iconSize}px`,
          }}
          onClick={interactive ? () => {
            setQuickRating(i);
            handleQuickRate(i);
          } : undefined}
          onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
          onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
        >
          {filled ? '★' : '☆'}
        </span>
      );
    }

    return <span style={{ display: 'flex', gap: '1px' }}>{stars}</span>;
  };

  const getRecommendationBadge = () => {
    if (!showRecommendationScore || !recommendationSources || recommendationSources.length === 0) {
      return null;
    }

    const badgeText = recommendationSources.includes('collaborative') && recommendationSources.includes('content')
      ? 'Perfect Match'
      : recommendationSources.includes('collaborative')
        ? 'Similar Users'
        : recommendationSources.includes('content')
          ? 'Your Taste'
          : 'Recommended';

    const badgeColor = recommendationSources.length > 1 
      ? '#4CAF50' 
      : recommendationSources.includes('collaborative')
        ? '#2196F3'
        : '#FF9800';

    return (
      <div 
        style={{
          position: 'absolute',
          top: '8px',
          right: '8px',
          backgroundColor: badgeColor,
          color: 'white',
          padding: '4px 8px',
          borderRadius: '12px',
          fontSize: '0.7rem',
          fontWeight: '600',
          zIndex: 2,
          textTransform: 'uppercase',
          letterSpacing: '0.5px',
        }}
      >
        {badgeText}
      </div>
    );
  };

  const formatYear = (year) => {
    return year ? `(${year})` : '';
  };

  const truncateTitle = (title, maxLength = 30) => {
    if (!title) return '';
    return title.length > maxLength ? `${title.substring(0, maxLength)}...` : title;
  };

  const truncatePlot = (plot, maxLength = 100) => {
    if (!plot) return '';
    return plot.length > maxLength ? `${plot.substring(0, maxLength)}...` : plot;
  };

  return (
    <div 
      style={{
        position: 'relative',
        background: 'rgba(255, 255, 255, 0.1)',
        backdropFilter: 'blur(20px)',
        borderRadius: '12px',
        boxShadow: '0 4px 15px rgba(0, 0, 0, 0.1)',
        transition: 'transform 0.3s ease, box-shadow 0.3s ease',
        overflow: 'hidden',
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        border: '1px solid rgba(255, 255, 255, 0.2)',
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-5px)';
        e.currentTarget.style.boxShadow = '0 8px 25px rgba(0, 0, 0, 0.15)';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 4px 15px rgba(0, 0, 0, 0.1)';
      }}
    >
      {getRecommendationBadge()}

      <div 
        onClick={() => {
          // Navigate to movie details
          console.log(`Navigate to /movies/${movieData.id}`);
        }}
        style={{ textDecoration: 'none', color: 'inherit', cursor: 'pointer' }}
      >
        <div style={{
          position: 'relative',
          overflow: 'hidden',
          aspectRatio: '2/3',
          background: '#f5f5f5',
        }}>
          <img
            src={movieData.poster_url || 'https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop'}
            alt={movieData.title}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              transition: 'transform 0.3s ease',
            }}
            onError={(e) => {
              e.target.src = 'https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop';
            }}
            onMouseEnter={(e) => {
              e.target.style.transform = 'scale(1.05)';
            }}
            onMouseLeave={(e) => {
              e.target.style.transform = 'scale(1)';
            }}
          />

          {/* Overlay with quick actions */}
          <div 
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              background: 'linear-gradient(to bottom, transparent 0%, transparent 50%, rgba(0, 0, 0, 0.7) 80%, rgba(0, 0, 0, 0.9) 100%)',
              opacity: 0,
              transition: 'opacity 0.3s ease',
              display: 'flex',
              flexDirection: 'column',
              justifyContent: 'flex-end',
              padding: '1rem',
              color: 'white',
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.opacity = '1';
              const content = e.currentTarget.querySelector('.overlay-content');
              if (content) {
                content.style.transform = 'translateY(0)';
              }
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.opacity = '0';
              const content = e.currentTarget.querySelector('.overlay-content');
              if (content) {
                content.style.transform = 'translateY(20px)';
              }
            }}
          >
            <div 
              className="overlay-content"
              style={{
                transform: 'translateY(20px)',
                transition: 'transform 0.3s ease',
              }}
            >
              <div style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                marginBottom: '0.5rem',
              }}>
                {renderStars(movieData.avg_rating)}
                <span style={{
                  fontSize: '0.8rem',
                  fontWeight: '600',
                }}>
                  {movieData.avg_rating ? movieData.avg_rating.toFixed(1) : 'No rating'}
                </span>
              </div>

              {movieData.plot && (
                <p style={{
                  fontSize: '0.8rem',
                  lineHeight: '1.3',
                  opacity: '0.9',
                  margin: '0',
                }}>
                  {truncatePlot(movieData.plot)}
                </p>
              )}
            </div>
          </div>
        </div>
      </div>

      <div style={{
        padding: '1rem',
        flex: 1,
        display: 'flex',
        flexDirection: 'column',
        gap: '0.5rem',
      }}>
        <div 
          onClick={() => {
            console.log(`Navigate to /movies/${movieData.id}`);
          }}
          style={{ textDecoration: 'none', color: 'inherit', cursor: 'pointer' }}
        >
          <h3 
            style={{
              fontSize: '1rem',
              fontWeight: '600',
              color: 'white',
              margin: '0',
              lineHeight: '1.2',
              transition: 'color 0.2s ease',
            }}
            title={movieData.title}
            onMouseEnter={(e) => {
              e.target.style.color = '#667eea';
            }}
            onMouseLeave={(e) => {
              e.target.style.color = 'white';
            }}
          >
            {truncateTitle(movieData.title)}
          </h3>
        </div>
        <p style={{
          fontSize: '0.85rem',
          color: '#666',
          margin: '0',
        }}>
          {formatYear(movieData.year)}
        </p>

        {/* User's rating if available */}
        {userRating && (
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '0.5rem',
            padding: '0.5rem',
            background: '#f8f9fa',
            borderRadius: '6px',
            borderLeft: '3px solid #667eea',
          }}>
            <span style={{
              fontSize: '0.75rem',
              color: '#667eea',
              fontWeight: '600',
            }}>Your rating:</span>
            {renderStars(userRating.rating)}
          </div>
        )}

        {/* Quick rating for authenticated users */}
        {isAuthenticated && !userRating && (
          <div style={{ marginTop: 'auto' }}>
            {!showQuickRate ? (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setShowQuickRate(true);
                }}
                disabled={isRating}
                style={{
                  width: '100%',
                  background: 'linear-gradient(135deg, #667eea, #764ba2)',
                  color: 'white',
                  border: 'none',
                  padding: '0.5rem',
                  borderRadius: '6px',
                  fontSize: '0.8rem',
                  cursor: 'pointer',
                  transition: 'opacity 0.2s ease',
                  opacity: isRating ? '0.6' : '1',
                }}
                onMouseEnter={(e) => {
                  if (!isRating) e.target.style.opacity = '0.9';
                }}
                onMouseLeave={(e) => {
                  if (!isRating) e.target.style.opacity = '1';
                }}
              >
                ⭐ Quick Rate
              </button>
            ) : (
              <div
                onClick={(e) => e.stopPropagation()}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '0.5rem',
                  padding: '0.5rem',
                  background: '#f8f9fa',
                  borderRadius: '6px',
                  border: '1px solid #e1e5e9',
                }}
              >
                <span style={{
                  fontSize: '0.75rem',
                  fontWeight: '600',
                  color: '#666',
                }}>Rate:</span>
                {renderStars(quickRating, true)}
                <button
                  onClick={() => setShowQuickRate(false)}
                  style={{
                    background: '#f44336',
                    color: 'white',
                    border: 'none',
                    width: '20px',
                    height: '20px',
                    borderRadius: '50%',
                    fontSize: '0.7rem',
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    transition: 'background-color 0.2s ease',
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.background = '#d32f2f';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.background = '#f44336';
                  }}
                >
                  ✕
                </button>
              </div>
            )}
          </div>
        )}

        {/* Movie metadata */}
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          gap: '0.25rem',
          marginTop: 'auto',
        }}>
          {movieData.rating_count > 0 && (
            <span style={{
              fontSize: '0.75rem',
              color: '#666',
            }}>
              {movieData.rating_count} rating{movieData.rating_count !== 1 ? 's' : ''}
            </span>
          )}

          {showRecommendationScore && movieData.recommendation_score && (
            <span style={{
              fontSize: '0.75rem',
              color: '#4CAF50',
              fontWeight: '600',
            }}>
              Match: {(movieData.recommendation_score * 100).toFixed(0)}%
            </span>
          )}
        </div>

        {/* Genres (if available) */}
        {movieData.genres && movieData.genres.length > 0 && (
          <div style={{
            display: 'flex',
            gap: '0.25rem',
            flexWrap: 'wrap',
            alignItems: 'center',
          }}>
            {movieData.genres.slice(0, 2).map(genre => (
              <span
                key={genre}
                style={{
                  background: '#e3f2fd',
                  color: '#1976d2',
                  padding: '2px 6px',
                  borderRadius: '10px',
                  fontSize: '0.65rem',
                  fontWeight: '500',
                }}
              >
                {genre}
              </span>
            ))}
            {movieData.genres.length > 2 && (
              <span style={{
                fontSize: '0.65rem',
                color: '#666',
                fontStyle: 'italic',
              }}>
                +{movieData.genres.length - 2}
              </span>
            )}
          </div>
        )}
      </div>

      {/* Loading overlay for rating */}
      {isRating && (
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'rgba(255, 255, 255, 0.9)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 10,
        }}>
          <div style={{
            width: '20px',
            height: '20px',
            border: '2px solid #f3f3f3',
            borderTop: '2px solid #667eea',
            borderRadius: '50%',
            animation: 'spin 1s linear infinite',
          }} />
        </div>
      )}

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

